    // 4. Notify target and verify observer was notified
    bool firstNotificationPassed = false;
    {
        // Reset observer state before first test
        observerNode->m_changed = false;
        observerNode->m_callCount = 0;

        // Notify source (which should trigger observer)
        sourceNode->notify(true);

        // Verify observer was notified
        if (observerNode->wasChanged() && observerNode->getCallCount() == 1) {
            firstNotificationPassed = true;
        }
